// Determine which follow-up step each lead needs
const leads = items[0].json.leads || [];
const now = Date.now();
const DAY = 86400000;

const actions = [];

for (const lead of leads) {
  const contacted = new Date(lead.updated_at || lead.created_at).getTime();
  const daysSince = Math.floor((now - contacted) / DAY);

  if (daysSince >= 3 && !lead.notes?.includes('followup_3')) {
    // Day 3: Follow-up email
    actions.push({
      ...lead,
      followup_step: 3,
      action: 'email',
      subject: `Following up — PM Travel Agency Partnership`,
      message: `Hi ${lead.name || 'Partner'},\n\nJust wanted to follow up on my earlier message about a potential partnership.\n\nWe've helped 50+ agencies worldwide offer Morocco tours to their clients. I'd love to share our B2B catalog.\n\nWould you have 5 minutes for a quick chat this week?\n\nBest,\nPM Travel Agency`
    });
  } else if (daysSince >= 2 && !lead.notes?.includes('followup_2')) {
    // Day 2: WhatsApp
    if (lead.phone) {
      actions.push({
        ...lead,
        followup_step: 2,
        action: 'whatsapp',
        message: `Hi ${lead.name || 'Partner'} 👋\n\nPM Travel Agency here. Did you get a chance to see our email about B2B Morocco tours?\n\nI can send you our catalog + rates right away if interested! 😊`
      });
    }
  } else if (daysSince >= 1 && !lead.notes?.includes('followup_1')) {
    // Day 1: Email
    actions.push({
      ...lead,
      followup_step: 1,
      action: 'email',
      subject: `Quick follow-up — Morocco tours`,
      message: `Hello ${lead.name || 'Partner'},\n\nI reached out yesterday about partnering for Morocco travel experiences.\n\nJust checking if this is something you'd be interested in exploring?\n\nHappy to answer any questions!\n\nBest regards,\nPM Travel Agency`
    });
  }
}

return actions.map(a => ({ json: a }));
